local P=game:GetService("Players")local LP=P.LocalPlayerlocal Mouse=LP:GetMouse()local RS=game:GetService("RunService")local TS=game:GetService("TweenService")local UIS=game:GetService("UserInputService")local C=workspace.CurrentCameralocal Lib=getgenv().EasyUILibrary if not Lib then return end
