Move:AddToggle("Speedhack (Быстрый бег)","SpeedOn",false)Move:AddSlider("Скорость","SpeedVal",16,500,50)Move:AddToggle("Super Jump","JumpOn",false)Move:AddSlider("Сила прыжка","JumpVal",50,500,100)Move:AddToggle("Полет (Fly)","FlyOn",false)Move:AddSlider("Скорость полета","FlySpeed",10,500,50)Move:AddToggle("Noclip (Сквозь стены)","Noclip",false)Move:AddToggle("Бесконечный прыжок","InfJump",false)Move:AddToggle("Auto Bhop (Распрыжка)","Bhop",false)Move:AddSlider("Задержка Bhop","BhopDelay",0,10,0)Move:AddToggle("Хождение по воздуху","AirWalk",false)Move:AddSlider("Высота AirWalk","AirWalkHeight",0,1000,50)Move:AddToggle("Хождение по воде","WaterWalk",false)Move:AddToggle("SafeWalk","SafeWalk",false)Move:AddToggle("SpinBot (Крутилка)","SpinBot",false)Move:AddSlider("Скорость SpinBot","SpinSpeed",10,200,50)Move:AddToggle("Анти-Регдолл","AntiRagdoll",false)Move:AddToggle("Левитация","Levitate",false)Move:AddToggle("Анти-замедление","AntiSlow",true)
