Vis:AddToggle("ESP Включить (Wallhack)","EspOn",false)Vis:AddToggle("ESP Боксы (Boxes)","EspBox",false)Vis:AddToggle("ESP Имена (Names)","EspName",false)Vis:AddToggle("ESP Здоровье (Health)","EspHP",false)Vis:AddToggle("ESP Броня (Armor)","EspArmor",false)Vis:AddToggle("ESP Дистанция","EspDist",false)Vis:AddToggle("ESP Оружие","EspWep",false)Vis:AddToggle("ESP Скелет","EspSkel",false)Vis:AddToggle("ESP Трейсеры (Линии)","EspTrace",false)Vis:AddToggle("Chams (Подсветка)","EspChams",false)Vis:AddSlider("Прозрачность Chams","ChTrans",0,10,5)Vis:AddToggle("Радар (2D Radar)","RadarOn",false)Vis:AddToggle("Светлая карта","Fullbright",false)Vis:AddToggle("Кастомное время","CustTime",false)Vis:AddSlider("Время суток (Часы)","TimeVal",0,24,12)Vis:AddToggle("Убрать туман (No Fog)","NoFog",false)Vis:AddToggle("Убрать тени","NoShadows",false)Vis:AddToggle("Убрать частицы","NoParticles",false)Vis:AddToggle("Прицел (Crosshair)","Crosshair",false)
local fovCircle=Drawing.new("Circle")fovCircle.Color=Color3.fromRGB(85,0,255)fovCircle.Thickness=1 fovCircle.Filled=false fovCircle.Transparency=1
local function getClosestPlayer()local target=nil local dist=getgenv().EasyConfig.AimFOV or 150 for _,p in ipairs(P:GetPlayers())do if p~=LP and p.Character and p.Character:FindFirstChild("Head")then local pos,onScreen=C:WorldToViewportPoint(p.Character.Head.Position)if onScreen then local d=(Vector2.new(pos.X,pos.Y)-Vector2.new(C.ViewportSize.X/2,C.ViewportSize.Y/2)).Magnitude if d<dist then target=p.Character.Head dist=d end end end end return target end
RS.RenderStepped:Connect(function()local Cfg=getgenv().EasyConfig if Cfg.ShowFOV then fovCircle.Position=Vector2.new(C.ViewportSize.X/2,C.ViewportSize.Y/2)fovCircle.Radius=Cfg.AimFOV fovCircle.Visible=true else fovCircle.Visible=false end local t=getClosestPlayer()if t and Cfg.AimEnabled and not Cfg.SilentAim then local s=math.clamp(Cfg.AimSmooth/10,0.1,1)C.CFrame=C.CFrame:Lerp(CFrame.new(C.CFrame.Position,t.Position),s)end end)
local oldNamecall;oldNamecall=hookmetamethod(game,"__namecall",function(self,...)local args={...}local method=getnamecallmethod()if method=="FindPartOnRayWithIgnoreList" or method=="FindPartOnRay" or method=="Raycast" then local Cfg=getgenv().EasyConfig if Cfg.SilentAim and math.random(1,100)<=Cfg.HitChance then local t=getClosestPlayer()if t then if method=="Raycast" then args[2]=(t.Position-args[1]).Unit*9999 else args[1]=t.Position end end end end return oldNamecall(self,unpack(args))end)
RS.Stepped:Connect(function()local Cfg=getgenv().EasyConfig local char=LP.Character if not char then return end local hum=char:FindFirstChildOfClass("Humanoid")local hrp=char:FindFirstChild("HumanoidRootPart")if hum then if Cfg.SpeedOn then hum.WalkSpeed=Cfg.SpeedVal end if Cfg.JumpOn then hum.JumpPower=Cfg.JumpVal hum.UseJumpPower=true end end if Cfg.Noclip and hrp then for _,p in ipairs(char:GetChildren())do if p:IsA("BasePart")then p.CanCollide=false end end end if Cfg.FlyOn and hrp then local lv=C.CFrame.LookVector local speed=Cfg.FlySpeed or 50 hrp.Velocity=Vector3.new(0,0.1,0)if UIS:IsKeyDown(Enum.KeyCode.W)then hrp.Velocity=lv*speed end if UIS:IsKeyDown(Enum.KeyCode.S)then hrp.Velocity=-lv*speed end end if Cfg.SpinBot and hrp then hrp.RotVelocity=Vector3.new(0,Cfg.SpinSpeed or 50,0)end end)
UIS.JumpRequest:Connect(function()if getgenv().EasyConfig.InfJump then local h=LP.Character and LP.Character:FindFirstChildOfClass("Humanoid")if h then h:ChangeState(Enum.HumanoidStateType.Jumping)end end end)
getgenv().ModulesLoaded=getgenv().ModulesLoaded+1 print("[EasyScript Module 1]: Боевые системы и физика перемещений успешно интегрированы.")
